  "inlineSchema": "// Prisma Schema - DEV Tickets\n// Compatible con SQLite (local) y Azure SQL Database (producción)\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel Role {\n  id          Int      @id @default(autoincrement())\n  name        String   @unique // USER | TECHNICIAN | SUPERVISOR | ADMIN\n  label       String // Usuario | Técnico | Supervisor | Administrador\n  description String?\n  createdAt   DateTime @default(now())\n  users       User[]\n\n  @@map(\"cfg_roles\")\n}\n\nmodel Sede {\n  id        Int      @id @default(autoincrement())\n  nombre    String // \"Cartago Dr. Max\"\n  serie     String // \"CART\" — prefijo para reportes\n  email     String   @unique // correo de la sede (cruce con usuario)\n  active    Boolean  @default(true)\n  createdAt DateTime @default(now())\n  users     User[]\n\n  @@map(\"Tbl_sedes\")\n}\n\nmodel User {\n  id               Int       @id @default(autoincrement())\n  name             String\n  email            String    @unique\n  password         String\n  roleId           Int\n  role             Role      @relation(fields: [roleId], references: [id])\n  sedeId           Int?\n  sede             Sede?     @relation(fields: [sedeId], references: [id])\n  active           Boolean   @default(true)\n  resetToken       String?\n  resetTokenExpiry DateTime?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n\n  requestedTickets   Ticket[]           @relation(\"Requestor\")\n  assignedTickets    Ticket[]           @relation(\"Assignee\")\n  comments           Comment[]\n  history            History[]\n  supervisorMentions TicketSupervisor[] @relation(\"SupervisorMentions\")\n\n  @@map(\"usr_users\")\n}\n\nmodel Ticket {\n  id             Int      @id @default(autoincrement())\n  title          String\n  description    String\n  priority       String   @default(\"MEDIUM\") // LOW | MEDIUM | HIGH | CRITICAL\n  status         String   @default(\"NEW\") // NEW | IN_REVIEW | IN_PROGRESS | IN_TESTING | COMPLETED\n  requestorId    Int\n  assigneeId     Int?\n  categoryId     Int?\n  subCategoryId  Int?\n  attachmentUrl  String?\n  attachmentName String?\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  requestor   User               @relation(\"Requestor\", fields: [requestorId], references: [id])\n  assignee    User?              @relation(\"Assignee\", fields: [assigneeId], references: [id])\n  category    Category?          @relation(fields: [categoryId], references: [id])\n  subCategory SubCategory?       @relation(fields: [subCategoryId], references: [id])\n  comments    Comment[]\n  history     History[]\n  supervisors TicketSupervisor[]\n\n  @@map(\"tkt_tickets\")\n}\n\n// Etiquetas de supervisor en un ticket\nmodel TicketSupervisor {\n  ticketId     Int\n  supervisorId Int\n  createdAt    DateTime @default(now())\n\n  ticket     Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n  supervisor User   @relation(\"SupervisorMentions\", fields: [supervisorId], references: [id])\n\n  @@id([ticketId, supervisorId])\n  @@map(\"tkt_supervisors\")\n}\n\nmodel Category {\n  id            Int           @id @default(autoincrement())\n  name          String        @unique\n  active        Boolean       @default(true)\n  createdAt     DateTime      @default(now())\n  subcategories SubCategory[]\n  tickets       Ticket[]\n\n  @@map(\"cfg_categories\")\n}\n\nmodel SubCategory {\n  id         Int      @id @default(autoincrement())\n  name       String\n  categoryId Int\n  active     Boolean  @default(true)\n  createdAt  DateTime @default(now())\n\n  category Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n  tickets  Ticket[]\n\n  @@unique([name, categoryId])\n  @@map(\"cfg_subcategories\")\n}\n\n// Configuración por prioridad: qué canales activar\nmodel NotificationSetting {\n  id           Int     @id @default(autoincrement())\n  priority     String  @unique // LOW | MEDIUM | HIGH | CRITICAL\n  emailEnabled Boolean @default(false)\n  smsEnabled   Boolean @default(false)\n\n  @@map(\"ntf_settings\")\n}\n\n// Lista de destinatarios (emails o teléfonos)\nmodel NotificationRecipient {\n  id        Int      @id @default(autoincrement())\n  type      String // email | sms\n  value     String // dirección de correo o número de teléfono\n  name      String   @default(\"\")\n  active    Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  @@map(\"ntf_recipients\")\n}\n\nmodel Comment {\n  id        Int      @id @default(autoincrement())\n  content   String\n  ticketId  Int\n  userId    Int\n  createdAt DateTime @default(now())\n\n  ticket Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n  user   User   @relation(fields: [userId], references: [id])\n\n  @@map(\"tkt_comments\")\n}\n\nmodel History {\n  id        Int      @id @default(autoincrement())\n  ticketId  Int\n  userId    Int\n  field     String\n  oldValue  String?\n  newValue  String?\n  createdAt DateTime @default(now())\n\n  ticket Ticket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n  user   User   @relation(fields: [userId], references: [id])\n\n  @@map(\"tkt_history\")\n}\n",
